'use client';

import { useEffect, useState } from 'react';
import { Box, Typography, Card, CardContent, Divider, List, ListItem, ListItemText } from '@mui/material';
import { QRCodeCanvas } from 'qrcode.react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Autoplay } from 'swiper/modules';
import { motion } from 'framer-motion';
import 'swiper/css';

type Order = {
  orderId: string;
  customerName?: string;
  companyName?: string;
  total: number;
  discount: number;
  payment: 'cash' | 'promptpay';
  status: 'pending' | 'paid';
  cart: { name: string; unitPrice: number; totalPrice: number; extra?: any }[];
};

export default function CustomerScreen() {
  const [order, setOrder] = useState<Order | null>(null);
  const promptpayId = process.env.NEXT_PUBLIC_PROMPTPAY_ID || '0625624598';

  // โหลดจาก localStorage + subscribe event
useEffect(() => {
  const handleStorage = () => {
    const str = localStorage.getItem('pendingOrder');
    if (str) {
      setOrder(JSON.parse(str));
    } else {
      setOrder(null); // 👉 reset กลับไป Banner
    }
  };
  window.addEventListener('storage', handleStorage);
  return () => window.removeEventListener('storage', handleStorage);
}, []);

  if (!order) {
    // 👉 State 1: Banner
    const banners = [
      { title: 'พิมพ์นามบัตรด่วน', img: '/banners/banner1.jpg' },
      { title: 'สติ๊กเกอร์เลเซอร์คมชัด', img: '/banners/banner2.jpg' },
      { title: 'โปสเตอร์ราคาพิเศษ', img: '/banners/banner3.jpg' },
    ];
    return (
      <Box sx={{ width: '100%', height: '100vh', bgcolor: '#000' }}>
        <Swiper modules={[Autoplay]} autoplay={{ delay: 5000 }} loop style={{ width: '100%', height: '100%' }}>
          {banners.map((item, idx) => (
            <SwiperSlide key={idx}>
              <Box
                sx={{
                  height: '100%',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  flexDirection: 'column',
                  background: `url(${item.img}) center/cover no-repeat`,
                  color: '#fff',
                  textShadow: '0 2px 6px rgba(0,0,0,0.7)',
                }}
              >
                <Typography variant="h3" fontWeight="bold">{item.title}</Typography>
              </Box>
            </SwiperSlide>
          ))}
        </Swiper>
      </Box>
    );
  }

  const total = (order.total ?? 0) - (order.discount ?? 0);

if (order.status === 'paid') {
  return (
    <Box
      sx={{
        width: '100%',
        height: '100vh',
        bgcolor: '#000',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        flexDirection: 'column',
        color: '#fff',
      }}
    >
      <motion.div
        initial={{ scale: 0.5, opacity: 0 }}
        animate={{ scale: 1.2, opacity: 1 }}
        transition={{ duration: 0.6 }}
      >
        <Typography variant="h3" color="success.main" fontWeight="bold">
          ✅ ชำระเงินเรียบร้อย
        </Typography>
      </motion.div>
      <Typography variant="h6" mt={2}>
        ขอบคุณที่ใช้บริการ Glossy Design
      </Typography>
    </Box>
  );
}

  // 👉 State 2: Pending
  return (
    <Box sx={{ maxWidth: 700, mx: 'auto', p: 4 }}>
      <Typography variant="h4" fontWeight="bold" gutterBottom>
        🧾 ใบสั่งซื้อ #{order.orderId}
      </Typography>
      <Card sx={{ mb: 3 }}>
        <CardContent>
          <Typography variant="subtitle1">ลูกค้า: {order.customerName || '-'}</Typography>
          <Typography variant="subtitle2" color="text.secondary">บริษัท: {order.companyName || '-'}</Typography>
          <Divider sx={{ my: 2 }} />
          <List>
            {order.cart?.map((item, idx) => (
              <ListItem key={idx} disableGutters>
                <ListItemText
                  primary={`${item.name} x${item.extra?.qty ?? 1}`}
                  secondary={`฿${item.totalPrice.toLocaleString('th-TH')}`}
                />
              </ListItem>
            ))}
          </List>
          <Divider sx={{ my: 2 }} />
          <Typography variant="h5" textAlign="right">
            รวมสุทธิ: ฿{total.toLocaleString('th-TH')}
          </Typography>
        </CardContent>
      </Card>

      {order.payment === 'promptpay' ? (
        <Box textAlign="center">
          <Typography variant="h6" gutterBottom>📱 สแกนเพื่อชำระเงิน</Typography>
          <QRCodeCanvas value={`promptpay://${promptpayId}?amount=${total}`} size={240} includeMargin />
        </Box>
      ) : (
        <Typography variant="h5" textAlign="center" color="success.main">
          💵 ชำระด้วยเงินสด
        </Typography>
      )}
    </Box>
  );
}
